// --- App Content Component ---
const AppContent: React.FC = () => {
    const { t } = useTranslations();
    const [view, setView] = useState('landing');
    const [showSplash, setShowSplash] = useState(true);
    const [isAuthenticated, setIsAuthenticated] = useState(false);
    const [scrollY, setScrollY] = useState(0);

    useEffect(() => {
        const handleScroll = () => {
            setScrollY(window.scrollY);
        };
        window.addEventListener('scroll', handleScroll, { passive: true });
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    useEffect(() => {
        const rootEl = document.getElementById('root');
        if (rootEl) {
            if (isAuthenticated) {
                rootEl.classList.add('dashboard-view');
            } else {
                rootEl.classList.remove('dashboard-view');
            }
        }
        return () => {
            if (rootEl) {
                rootEl.classList.remove('dashboard-view');
            }
        };
    }, [isAuthenticated]);

    const handleEnterApp = () => setShowSplash(false);
    const handleNavigateToLanding = () => { window.scrollTo(0, 0); setView('landing'); };
    const handleNavigateToLogin = () => { window.scrollTo(0, 0); setView('login'); };
    const handleNavigateToAgreement = () => { window.scrollTo(0, 0); setView('consultant-agreement'); };
    const handleNavigateToCalendar = () => { window.scrollTo(0, 0); setView('event-calendar'); };
    const handleNavigateToBookRelease = () => { window.scrollTo(0, 0); setView('book-release'); };
    const handleNavigateToMembershipPromo = () => { window.scrollTo(0, 0); setView('membership-promo'); };
    const handleNavigateToContactBooking = () => { window.scrollTo(0, 0); setView('contact-booking'); }; // New navigation handler

    const handleNavigateToApplication = () => {
        setView('landing');
        // Use setTimeout to allow landing page to render before scrolling
        setTimeout(() => {
            const el = document.getElementById('ansokan');
            if (el) {
                const headerOffset = 100;
                const elementPosition = el.getBoundingClientRect().top;
                const offsetPosition = elementPosition + window.scrollY - headerOffset;
                window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
            }
        }, 100);
    };

    const handleLoginSuccess = () => { setIsAuthenticated(true); };
    const handleLogout = () => { setIsAuthenticated(false); setView('landing'); };

    if (showSplash) {
        return <SplashScreen onEnter={handleEnterApp} />;
    }

    if (isAuthenticated) {
        return <BoardMemberPage onLogout={handleLogout} />;
    }

    if (view === 'consultant-agreement') {
        return <ConsultantAgreement onBack={handleNavigateToLanding} />;
    }

    if (view === 'event-calendar') {
        return <EventCalendarView onBack={handleNavigateToLanding} />;
    }

    if (view === 'book-release') {
        return <BookReleasePage onBack={handleNavigateToLanding} />;
    }

    if (view === 'membership-promo') {
        return <MembershipPromo onNavigateToApplication={handleNavigateToApplication} onBack={handleNavigateToLanding} />;
    }

    if (view === 'contact-booking') {
        return <ContactAndBookingPage onBack={handleNavigateToLanding} />; // Render new page
    }

    return (
      <div className="bg-gray-50/60 dark:bg-slate-900/60 backdrop-blur-lg text-gray-800 dark:text-slate-200 antialiased flex flex-col min-h-screen relative">
         <div 
            className="absolute top-0 -left-4 w-72 h-72"
            style={{ transform: `translateY(${scrollY * 0.4}px)` }}
            >
            <div className="w-full h-full bg-cyan-500 rounded-full mix-blend-lighten filter blur-xl opacity-40 dark:opacity-70 animate-blob"></div>
         </div>
         <div 
            className="absolute top-0 -right-4 w-72 h-72"
            style={{ transform: `translateY(${scrollY * 0.2}px)` }}
         >
            <div className="w-full h-full bg-amber-300 rounded-full mix-blend-lighten filter blur-xl opacity-40 dark:opacity-70 animate-blob animation-delay-2000"></div>
         </div>
         <div 
            className="absolute -bottom-8 left-20 w-72 h-72"
            style={{ transform: `translateY(${scrollY * -0.3}px)` }}
         >
            <div className="w-full h-full bg-yellow-300 rounded-full mix-blend-lighten filter blur-xl opacity-40 dark:opacity-70 animate-blob animation-delay-4000"></div>
         </div>

        <main className="flex-grow relative z-10">
          {view === 'landing' && (
              <LandingPage 
                  onNavigateToLogin={handleNavigateToLogin} 
                  onNavigateToAgreement={handleNavigateToAgreement}
                  onNavigateToCalendar={handleNavigateToCalendar}
                  onNavigateToBookRelease={handleNavigateToBookRelease}
                  onNavigateToMembershipPromo={handleNavigateToMembershipPromo}
                  onNavigateToContactBooking={handleNavigateToContactBooking}
              />
          )}
          {view === 'login' && <LoginForm onLoginSuccess={handleLoginSuccess} onBackClick={handleNavigateToLanding} />}
        </main>

        <footer className="bg-slate-900/80 backdrop-blur-lg text-slate-200 py-8 border-t border-slate-700/50 relative z-10">
          <div className="container mx-auto px-6 text-center">
             <div className="flex justify-center items-center gap-x-6 mb-6">
                <LanguageSelector />
                <ThemeToggle />
            </div>
            <p className="text-sm">&copy; {new Date().getFullYear()} {t.footerCopyright}</p>
            <div className="flex justify-center gap-x-6 my-6">
              <div className="relative group flex items-center">
                <a href="https://www.facebook.com" target="_blank" rel="noopener noreferrer" aria-label={t.facebookAria} className="text-slate-400 hover:text-white transition-all duration-300 transform hover:scale-110">
                  <FacebookIcon />
                </a>
                <div className="absolute bottom-full mb-2 px-3 py-1.5 text-sm font-semibold text-white bg-slate-800 rounded-lg shadow-lg opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none whitespace-nowrap left-1/2 -translate-x-1/2">
                  {t.facebookAria}
                </div>
              </div>
              <div className="relative group flex items-center">
                <a href="https://www.instagram.com" target="_blank" rel="noopener noreferrer" aria-label={t.instagramAria} className="text-slate-400 hover:text-white transition-all duration-300 transform hover:scale-110">
                  <InstagramIcon />
